import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, getDocs } from 'firebase/firestore';

function TeamLineup() {
  const { teamId } = useParams();
  const navigate = useNavigate();
  const [teamData, setTeamData] = useState(null);
  const [players, setPlayers] = useState([]);
  const [lineup, setLineup] = useState([]);
  const [pinVerified, setPinVerified] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      const teamRef = doc(db, 'teams', teamId);
      const teamSnap = await getDoc(teamRef);
      if (teamSnap.exists()) {
        setTeamData(teamSnap.data());
        setLineup(Array(teamSnap.data().playerCount).fill(null));
      }

      const playersSnap = await getDocs(collection(db, 'players'));
      const playersData = playersSnap.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
      }));
      setPlayers(playersData);
    };

    fetchData();
  }, [teamId]);

  const verifyPin = () => {
    const userPin = prompt("Enter PIN:");
    if (userPin === teamData.pin) {
      setPinVerified(true);
    } else {
      alert("Incorrect PIN.");
      navigate('/teams-management');
    }
  };

  const handleSelectPlayer = (index) => {
    const playerNames = players.map(p => `${p.firstName} ${p.lastName}`).join('\n');
    const selectedName = prompt(`Select a player:\n${playerNames}`);
    const selectedPlayer = players.find(p => `${p.firstName} ${p.lastName}` === selectedName);

    if (selectedPlayer) {
      const updatedLineup = [...lineup];
      updatedLineup[index] = selectedPlayer;
      setLineup(updatedLineup);
    }
  };

  if (!pinVerified) {
    verifyPin();
    return null;
  }

  return (
    <div style={styles.container}>
      <h1>{teamData.name} - Lineup</h1>
      <img
        src={`${process.env.PUBLIC_URL}/images/Tactics/${teamData.playerCount}_players_${teamData.tactic}.png`}
        alt="Tactic"
        style={styles.tacticImage}
      />

      <div style={styles.lineupContainer}>
        {lineup.map((player, index) => (
          <div key={index} style={styles.slot} onClick={() => handleSelectPlayer(index)}>
            {player ? (
              <>
                <img src={player.profilePicture || `${process.env.PUBLIC_URL}/images/profile_picture.jpg`} alt="Player" />
                <p>{player.firstName} {player.lastName}</p>
                <p>{player.favoritePosition}</p>
                <p>Power: {player.powerRating}</p>
              </>
            ) : <p>+ Slot {index + 1}</p>}
          </div>
        ))}
      </div>

      <button style={styles.backButton} onClick={() => navigate('/teams-management')}>Back</button>
    </div>
  );
}

const styles = {
  container: { padding: '20px', textAlign: 'center' },
  tacticImage: { width: '50%' },
  lineupContainer: { display: 'flex', gap: '10px' },
  slot: { width: '100px', height: '100px', backgroundColor: '#ddd', cursor: 'pointer' },
  backButton: { marginTop: '20px' },
};

export default TeamLineup;
